mapper.select:
select * from ygt_group_order

    and ygt_go_campaign_id = #{campaignId}
    and ygt_go_group_id = #{groupId}
    and ygt_go_status = #{status}

order by ygt_group_order_id desc
limit #{offset}, #{limit}

mapper.update:
update ygt_group_order
ygt_go_status = #{ygtGoStatus}, ygt_go_total_amount = #{ygtGoTotalAmount}, ygt_go_remark = #{ygtGoRemark}, ygt_go_update_time = now()
where ygt_group_order_id = #{ygtGroupOrderId}
